6	<title>우리WON카 — Diver7 신차추천 데모</title>
7	<style>
8	  @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap');
9	  * { box-sizing: border-box; margin: 0; padding: 0; }
10	  body { font-family: 'Noto Sans KR', sans-serif; background: #f4f5f7; font-size: 13px; color: #1a1a2e; }
11	
12	  /* TOP BAR */
13	  .top-bar { background: #fff; border-bottom: 1px solid #e0e0e0; padding: 6px 20px; display: flex; align-items: center; gap: 8px; justify-content: flex-end; font-size: 12px; }
14	  .user-select { background: #fff; border: 1px solid #d0d0d0; border-radius: 4px; padding: 4px 10px; font-size: 12px; cursor: pointer; display: inline-flex; align-items: center; gap: 5px; min-width: 92px; font-family: inherit; }
15	  .dot { width: 8px; height: 8px; border-radius: 50%; }
16	  .dot-a { background: #4f8ef7; }
17	  .dot-b { background: #28c76f; }
18	  .btn-apply { background: #1a56db; color: #fff; border: none; border-radius: 4px; padding: 5px 14px; font-size: 12px; font-weight: 700; cursor: pointer; font-family: inherit; }
19	  .btn-apply:hover { background: #1648c2; }
20	
21	  /* HEADER */
22	  .header { background: #fff; border-bottom: 1px solid #e8e8e8; padding: 10px 20px; display: flex; align-items: center; }
23	  .logo { font-size: 24px; font-weight: 900; color: #002366; letter-spacing: -0.04em; margin-right: 18px; white-space: nowrap; }
24	  .logo .won { color: #1a56db; }
25	  .search-wrap { flex: 1; max-width: 480px; border: 2px solid #5a8dee; border-radius: 22px; display: flex; align-items: center; padding: 6px 16px; }
26	  .search-wrap input { border: none; outline: none; flex: 1; font-size: 13px; font-family: inherit; }
27	  .header-nav { margin-left: auto; display: flex; gap: 22px; }
28	  .nav-item { display: flex; flex-direction: column; align-items: center; gap: 2px; cursor: pointer; font-size: 11px; color: #555; }
29	  .nav-item svg { width: 20px; height: 20px; }
30	
31	  /* LAYOUT */
32	  .layout { display: flex; height: calc(100vh - 84px); overflow: hidden; }
33	  .main { flex: 1; overflow-y: auto; padding: 14px 16px; }
34	  .sidebar { width: 244px; min-width: 244px; background: #fff; border-left: 1px solid #e8e8e8; display: flex; flex-direction: column; }
35	
36	  /* BANNER */
37	  .banner { border-radius: 12px; overflow: hidden; background: linear-gradient(130deg,#0d1b4b 0%,#1a3278 45%,#2563eb 80%,#5a8dee 100%); position: relative; margin-bottom: 16px; min-height: 160px; display: flex; align-items: center; padding: 28px 36px; }
38	  .banner-txt h2 { font-size: 22px; font-weight: 900; color: #fff; letter-spacing: -0.03em; line-height: 1.25; margin-bottom: 6px; }
39	  .banner-txt p { font-size: 12px; color: rgba(255,255,255,.75); margin-bottom: 14px; }
40	  .banner-badge { display: inline-block; background: rgba(255,255,255,.18); border: 1px solid rgba(255,255,255,.4); color: #fff; border-radius: 20px; padding: 4px 14px; font-size: 11px; font-weight: 700; }
41	  .banner-deco { position: absolute; right: 0; top: 0; bottom: 0; width: 48%; opacity: .18; display: flex; align-items: center; justify-content: center; font-size: 100px; }
42	
43	  /* SECTION */
44	  .sec-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
45	  .sec-label { display: flex; align-items: center; gap: 7px; margin-bottom: 10px; }
46	  .badge { color: #fff; font-size: 10px; font-weight: 700; border-radius: 4px; padding: 2px 8px; }
47	  .badge-a { background: linear-gradient(90deg,#1a56db,#5a8dee); }
48	  .badge-b { background: linear-gradient(90deg,#28c76f,#48d98a); }
49	  .sec-title { font-size: 13px; font-weight: 700; }
50	  .name-a { color: #1a56db; }
51	  .name-b { color: #28c76f; }
52	
53	  /* CAR CARDS */
54	  .car-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
55	  .car-card { background: #fff; border: 1px solid #e8e8e8; border-radius: 10px; overflow: hidden; cursor: pointer; transition: box-shadow .2s, transform .15s; }
56	  .car-card:hover { box-shadow: 0 4px 18px rgba(26,86,219,.13); transform: translateY(-2px); }
57	
58	  /* IMAGE AREA */
59	  .car-img { position: relative; height: 140px; background: #000; display: flex; align-items: center; justify-content: center; overflow: hidden; }
60	  .car-img img { width: 100%; height: 100%; object-fit: contain; object-position: center; }
61	  .img-tag { position: absolute; top: 7px; left: 7px; font-size: 9px; font-weight: 700; border-radius: 3px; padding: 2px 6px; }
62	  .tag-k { background: rgba(26,86,219,.25); color: #60a5fa; border: 1px solid rgba(96,165,250,.4); }
63	  .tag-i { background: rgba(255,152,0,.2); color: #fbbf24; border: 1px solid rgba(251,191,36,.4); }
64	  .tag-h { background: rgba(40,199,111,.2); color: #48d98a; border: 1px solid rgba(72,217,138,.4); }
65	  .img-btns { position: absolute; bottom: 8px; left: 0; right: 0; display: flex; gap: 5px; padding: 0 8px; }
66	  .ib { flex: 1; background: rgba(255,255,255,.9); border: none; border-radius: 5px; padding: 5px 0; font-size: 10px; font-weight: 600; cursor: pointer; font-family: inherit; }
67	  .ib:hover { background: #fff; }
68	
69	  /* CARD INFO */
70	  .car-info { padding: 8px 10px 10px; }
71	  .car-brand { font-size: 10px; color: #aaa; margin-bottom: 1px; }
72	  .car-name { font-size: 12px; font-weight: 700; color: #1a1a2e; margin-bottom: 3px; line-height: 1.35; }
73	  .car-spec { font-size: 10px; color: #999; margin-bottom: 5px; }
74	  .price-row { display: flex; align-items: baseline; gap: 3px; }
75	  .price { font-size: 15px; font-weight: 900; }
76	  .price-unit { font-size: 10px; color: #888; }
77	  .price-sub { font-size: 10px; color: #bbb; margin-top: 2px; }
78	
79	  /* SIDEBAR */
80	  .sb-top { padding: 12px 12px 8px; border-bottom: 1px solid #f0f0f0; display: flex; align-items: flex-start; gap: 9px; }
81	  .sb-avatar { width: 38px; height: 38px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 17px; flex-shrink: 0; }
82	  .av-a { background: linear-gradient(135deg,#4f8ef7,#1a56db); }
83	  .av-b { background: linear-gradient(135deg,#48d98a,#28c76f); }
84	  .sb-info { flex: 1; }
85	  .sb-name { font-size: 13px; font-weight: 700; }
86	  .sb-meta { font-size: 11px; color: #888; margin-top: 1px; }
87	  .sb-interest { font-size: 10px; color: #555; margin-top: 2px; }
88	  .sb-nav { display: flex; gap: 2px; margin-left: auto; }
89	  .sb-nav button { background: none; border: none; color: #bbb; font-size: 14px; cursor: pointer; padding: 2px; }
90	
91	  .credit-box { margin: 8px 12px; background: linear-gradient(135deg,#eef2ff,#f0fdf4); border-radius: 8px; padding: 8px 11px; display: flex; align-items: center; gap: 8px; }
92	  .cr-score { font-size: 20px; font-weight: 900; color: #1a56db; }
93	  .cr-info { font-size: 10px; color: #666; line-height: 1.5; }
94	  .cr-info strong { display: block; font-size: 11px; color: #333; }
95	  .cr-loan { margin-left: auto; text-align: right; }
96	  .cr-amt { font-size: 12px; font-weight: 700; color: #28c76f; }
97	  .cr-lbl { font-size: 9px; color: #aaa; }
98	
99	  .cur-car { margin: 0 12px 8px; font-size: 11px; background: #f8f9fa; border-radius: 6px; padding: 6px 10px; color: #555; }
100	  .cur-car strong { color: #1a1a2e; }
101	
102	  .j-hdr { padding: 7px 12px 3px; display: flex; align-items: center; justify-content: space-between; }
103	  .j-title { font-size: 12px; font-weight: 700; }
104	  .j-all { font-size: 10px; color: #1a56db; cursor: pointer; display: flex; align-items: center; gap: 3px; }
105	  .j-ck { width: 14px; height: 14px; background: #1a56db; border-radius: 3px; display: flex; align-items: center; justify-content: center; }
106	  .j-tabs { display: flex; padding: 0 12px; border-bottom: 1px solid #f0f0f0; }
107	  .jtab { font-size: 10px; padding: 5px 4px; cursor: pointer; color: #bbb; border-bottom: 2px solid transparent; white-space: nowrap; transition: all .15s; }
108	  .jtab.on { color: #1a56db; border-bottom-color: #1a56db; font-weight: 700; }
109	  .j-list { flex: 1; overflow-y: auto; padding: 4px 12px; }
110	  .j-item { display: flex; gap: 8px; padding: 7px 0; border-bottom: 1px solid #f5f5f5; align-items: flex-start; }
111	  .j-thumb { width: 38px; height: 38px; border-radius: 6px; background: #f0f4ff; display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; }
112	  .j-tag { font-size: 9px; font-weight: 700; background: #eef2ff; color: #1a56db; border-radius: 3px; padding: 1px 5px; margin-bottom: 2px; display: inline-block; }
113	  .j-name { font-size: 11px; font-weight: 600; color: #333; }
