116	  .sb-btm { padding: 9px 12px; border-top: 1px solid #f0f0f0; display: grid; grid-template-columns: repeat(4,1fr); gap: 3px; }
117	  .sb-icon { display: flex; flex-direction: column; align-items: center; gap: 3px; cursor: pointer; padding: 5px 2px; border-radius: 7px; }
118	  .sb-icon:hover { background: #f0f4ff; }
119	  .sb-ico { width: 28px; height: 28px; border-radius: 7px; display: flex; align-items: center; justify-content: center; font-size: 13px; }
120	  .sb-lbl { font-size: 9px; color: #555; text-align: center; line-height: 1.3; }
121	
122	  ::-webkit-scrollbar { width: 3px; }
123	  ::-webkit-scrollbar-thumb { background: #ddd; border-radius: 3px; }
