146	function playScenario() {
147	  if (scenarioRunning) return;
148	  scenarioRunning = true;
149	
150	  var body = document.querySelector(".cl-body");
151	  var progressBars = document.querySelectorAll(".prog-step");
152	  var progressLabel = document.querySelector(".prog-label");
153	
154	  for (var i = 0; i < SCENARIO.length; i++) {
155	    var step = SCENARIO[i];
156	
157	    (function(index, stepData) {
158	      var delay = stepData.delay || 0;
159	
160	      setTimeout(function() {
161	        if (stepData.type === "agent") {
162	          addBotMessage(body, stepData.text);
163	        } else if (stepData.type === "user") {
164	          addUserMessage(body, stepData.text);
165	        } else if (stepData.type === "progress") {
166	          updateProgressBar(progressBars, stepData.index, progressLabel);
167	        } else if (stepData.type === "summary") {
168	          addSummaryBox(body, stepData.items);
169	        } else if (stepData.type === "rec") {
170	          addRecommendations(body, stepData.cars);
171	        } else if (stepData.type === "typing") {
172	          addTypingIndicator(body);
173	          setTimeout(function() {
174	            removeTypingIndicator(body);
175	          }, 1500);
176	        }
177	      }, delay);
178	    })(i, step);
179	  }
180	}
