32	function initSearch() {
33	  // search_data.js에서 SEARCH_QUERIES를 전역으로 제공
34	  if (typeof SEARCH_QUERIES !== 'undefined') {
35	    searchQueries = SEARCH_QUERIES;
36	    console.log('검색 질의 로드됨:', searchQueries.length, '개');
37	    return true;
38	  } else {
39	    console.error('SEARCH_QUERIES 데이터를 찾을 수 없습니다. search_data.js가 로드되었나요?');
40	    return false;
41	  }
42	}
