44	/**
45	 * 검색 입력 핸들러 (디바운스 적용)
46	 */
47	function handleSearchInput(inputValue) {
48	  clearTimeout(searchDebounceTimer);
49	
50	  searchDebounceTimer = setTimeout(() => {
51	    performSearch(inputValue);
52	  }, 500); // 0.5초 디바운스
53	}
