55	/**
56	 * 검색 수행
57	 */
58	async function performSearch(query) {
59	  const cleanQuery = query.trim().toLowerCase();
60	
61	  // 빈 검색: 기본 상태로 복귀
62	  if (!cleanQuery) {
63	    showDefaultResults();
64	    return;
65	  }
66	
67	  // 키워드 토크나이즈
68	  const keywords = cleanQuery.split(/\s+/);
69	
70	  // 각 질의와 매칭 점수 계산
71	  const matches = searchQueries.map(q => {
72	    const intersection = keywords.filter(k =>
73	      q.keywords.some(qk => qk.includes(k) || k.includes(qk.substring(0, 2)))
74	    );
75	    return {
76	      ...q,
77	      score: intersection.length
78	    };
79	  }).filter(m => m.score > 0);
80	
81	  // 점수 높은 순으로 정렬
82	  matches.sort((a, b) => b.score - a.score);
83	
84	  if (matches.length === 0) {
85	    showNoResults(keywords);
86	  } else {
87	    await displaySearchResults(matches);
88	  }
89	}
