91	/**
92	 * 검색 결과 표시 (복수 결과셋)
93	 * search_data.js의 SEARCH_RESULTS 객체에서 데이터 직접 사용
94	 */
95	function displaySearchResults(matches) {
96	  const resultsContainer = document.getElementById('search-results-container');
97	
98	  if (!resultsContainer) {
99	    console.error('검색 결과 컨테이너 없음');
100	    return;
101	  }
102	
103	  // 기본 추천 섹션 숨기기
104	  const recommendedSection = document.getElementById('recommended-section');
105	  if (recommendedSection) {
106	    recommendedSection.style.display = 'none';
107	  }
108	
109	  resultsContainer.innerHTML = '';
110	  resultsContainer.style.display = 'block';
111	
112	  // 각 결과셋 렌더링
113	  for (const match of matches) {
114	    if (typeof SEARCH_RESULTS !== 'undefined' && SEARCH_RESULTS[match.id]) {
115	      const resultData = SEARCH_RESULTS[match.id];
116	      const section = createSearchResultSection(resultData, match.score);
117	      resultsContainer.appendChild(section);
118	    } else {
119	      console.error(`결과셋을 찾을 수 없음 (${match.id})`);
120	    }
121	  }
122	}
