124	/**
125	 * 검색 결과 섹션 HTML 생성
126	 */
127	function createSearchResultSection(resultData, score) {
128	  const section = document.createElement('div');
129	  section.className = 'search-result-section';
130	  section.innerHTML = `
131	    <div class="search-result-header">
132	      <h3>${resultData.title}</h3>
133	      <p class="search-result-desc">${resultData.description}</p>
134	    </div>
135	    <div class="prod-grid" id="search-grid-${resultData.queryId}">
136	      ${resultData.cars.map(car => `
137	        <div class="prod-card">
138	          <div class="pc-img">
139	            <img src="${CAR_IMGS[car.img]}" alt="${car.name}" style="max-width:100%; max-height:100%; object-fit:contain;">
140	            <span class="pc-tag ${car.tagC}">${car.tag}</span>
141	            <div class="pc-btns">
142	              <button class="pc-btn" onclick="viewDetails('${car.img}')">상세</button>
143	              <button class="pc-btn" onclick="selectProduct('${car.img}')">선택</button>
144	            </div>
145	          </div>
146	          <div class="pc-info">
147	            <div class="pc-brand">${car.brand}</div>
148	            <div class="pc-name">${car.name}</div>
149	            <div class="pc-spec">${car.spec}</div>
150	            <div class="pc-price">${car.price}</div>
151	            <div style="font-size:10px;color:#1a56db;margin-top:5px;font-weight:700;">★ ${car.highlight}</div>
152	          </div>
153	        </div>
154	      `).join('')}
155	    </div>
156	  `;
157	
158	  return section;
159	}
