161	/**
162	 * 검색 결과 없음 표시
163	 */
164	function showNoResults(keywords) {
165	  const resultsContainer = document.getElementById('search-results-container');
166	
167	  if (!resultsContainer) return;
168	
169	  const recommendedSection = document.getElementById('recommended-section');
170	  if (recommendedSection) {
171	    recommendedSection.style.display = 'none';
172	  }
173	
174	  resultsContainer.innerHTML = `
175	    <div class="search-no-result">
176	      <div class="no-result-icon">🔍</div>
177	      <div class="no-result-text">"${keywords.join(' ')}"에 맞는 검색 결과가 없습니다.</div>
178	      <div class="no-result-subtitle">다른 검색어를 시도해보세요.</div>
179	      <div class="search-suggestions">
180	        <div class="suggestion-title">추천 검색어:</div>
181	        <div class="suggestion-chips">
182	          ${searchQueries.map(q => `
183	            <div class="suggestion-chip" onclick="document.querySelector('#search-input').value='${q.label}'; handleSearchInput('${q.label}')">
184	              ${q.description}
185	            </div>
186	          `).join('')}
187	        </div>
188	      </div>
189	    </div>
190	  `;
191	
192	  resultsContainer.style.display = 'block';
193	}
